function vp_json($s,$m='',$e=array()){header('Content-Type: application/json');echo json_encode(array_merge(array('status'=>$s,'message'=>$m),$e));exit;}
function vp_params(){ $st=$_REQUEST['start_date']??date('Y-m-01');$en=$_REQUEST['end_date']??date('Y-m-d');if(!vp_valid_date($st)||!vp_valid_date($en)||$st>$en)throw new Exception('Periode tanggal tidak valid.');return array($st,$en,trim($_REQUEST['status']??''),trim($_REQUEST['vendor_code']??''));}
function vp_list($db,$st,$en,$status,$vendor){$w="vp.posting_date BETWEEN ? AND ?";$p=array($st,$en);if($status!==''){$w.=" AND vp.status=?";$p[]=$status;}if($vendor!==''){$w.=" AND vp.vendor_code=?";$p[]=$vendor;}return $db->query("SELECT vp.*,v.nama vendor_name,ba.nama_rek bank_account_name,aa.nama_rek ap_account_name,jh.no_jurnal FROM erp_vendor_payment vp LEFT JOIN pemasok v ON v.kode_pemasok=vp.vendor_code LEFT JOIN rekening ba ON ba.no_rek=vp.bank_account LEFT JOIN rekening aa ON aa.no_rek=vp.ap_account LEFT JOIN jurnal_header jh ON jh.id=vp.journal_header_id WHERE $w ORDER BY vp.posting_date DESC,vp.id DESC",$p);}
function vp_invoice_open_row($db,$id){return $db->fetch("SELECT vi.*,v.nama vendor_name,COALESCE((SELECT SUM(vp.amount) FROM erp_vendor_payment vp WHERE vp.vendor_invoice_id=vi.id AND vp.status='POSTED'),0) paid_amount FROM erp_vendor_invoice vi LEFT JOIN pemasok v ON v.kode_pemasok=vi.vendor_code WHERE vi.id=? LIMIT 1",array($id));}

$act=$_GET['act']??'';
