  else{if($db->fetch("SELECT id FROM erp_vendor_payment WHERE vendor_payment_no=? LIMIT 1",array($no)))throw new Exception('Nomor vendor payment sudah digunakan.');$data['status']='DRAFT';$data['created_by']=vp_user();$data['created_at']=date('Y-m-d H:i:s');$db->insert('erp_vendor_payment',$data);$id=$db->last_insert_id();}
